<div class="emoji-picker">
    @foreach (var emoji in Emojis)
    {
        <button class="emoji-option" @onclick="() => SelectEmoji(emoji)" @onclick:stopPropagation>
            @emoji
        </button>
    }
</div>

@code {
    [Parameter] public EventCallback<string> OnEmojiSelected { get; set; }

    private static readonly string[] Emojis = ["👍", "❤️", "😂", "🎉", "😮", "😢"];

    private async Task SelectEmoji(string emoji) => await OnEmojiSelected.InvokeAsync(emoji);
}
"}

{"path": "/tmp/sv-249395442d424159841db0bfe9bd3989/Components/Pages/Chat/MessageInput.razor", "file_text": "
<div class="message-input">
    <textarea @bind="Text" @bind:event="oninput" placeholder="@Placeholder"
              @onkeydown="HandleKeyDown" rows="2"></textarea>
    <button class="send-button" @onclick="Submit" disabled="@string.IsNullOrWhiteSpace(Text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSubmit { get; set; }

    private string Text { get; set; } = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Submit();
        }
    }

    private async Task Submit()
    {
        if (string.IsNullOrWhiteSpace(Text)) return;
        var message = Text.Trim();
        Text = "";
        await OnSubmit.InvokeAsync(message);
    }
}
"}

