arguments.file_text:
@page "/chat"
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="channels"
                    ActiveChannelId="activeChannelId"
                    OnChannelSelected="SelectChannel" />

    @if (activeChannel is not null)
    {
        <div class="chat-main @(isThreadOpen ? "thread-open" : "")">
            <MessageArea ChannelName="@activeChannel.Name"
                         ChannelDescription="@activeChannel.Description"
                         Messages="messages"
                         ThreadSummaries="threadSummaries"
                         OnLoadMore="LoadOlderMessages"
                         OnSendMessage="SendMessage"
                         OnOpenThread="OpenThread"
                         OnReaction="HandleReaction" />
        </div>

        @if (isThreadOpen)
        {
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnSendReply="SendThreadReply"
                         OnClose="CloseThread" />
        }
    }
</div>

@code {
    private List<Channel> channels = [];
    private Channel? activeChannel;
    private int activeChannelId;

    private List<Message> messages = [];
    private List<ThreadSummary> threadSummaries = [];
    private int messageSkip;
    private const int PageSize = 30;

    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0]);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        activeChannel = channel;
        activeChannelId = channel.Id;
        messageSkip = 0;
        isThreadOpen = false;

        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        messageSkip = messages.Count;

        BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channels to update unread counts
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadOlderMessages()
    {
        if (activeChannel is null) return;

        var older = await ChatService.GetMessagesAsync(activeChannel.Id, messageSkip, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            messageSkip += older.Count;
            BuildThreadSummaries();
        }
    }

    private async Task SendMessage(string content)
    {
        if (activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(activeChannel.Id, content, null);
        messages.Add(sent);
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        isThreadOpen = true;
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (activeChannel is null || threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannel.Id, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update thread summary in main view
        BuildThreadSummaries();
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to show updated reactions
        if (activeChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(activeChannel.Id, 0, messageSkip);
        }
    }

    private void BuildThreadSummaries()
    {
        var replies = messages.Where(m => m.ReplyToId is not null).ToList();
