.message-reactions {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    background: #e8eaed;
    border-radius: 12px;
    font-size: 0.8rem;
    cursor: default;
    border: 1px solid #d0d3d8;
}

