    top: 4px;
    right: 8px;
    display: flex;
    gap: 4px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px 4px;
    box-shadow: 0 2px 6px rgba(0,0,0,0.1);
}

.action-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    font-size: 0.8rem;
    white-space: nowrap;
}

.action-btn:hover {
    background: #eee;
}

