.emoji-picker {
    display: flex;
    gap: 4px;
    padding: 6px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.12);
    width: fit-content;
    margin-top: 4px;
}

.emoji-option {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px;
    border-radius: 4px;
    line-height: 1;
}

.emoji-option:hover {
    background: #eee;
}

