    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    color: #666;
}

.close-btn:hover {
    background: #eee;
    color: #111;
}

.thread-root-message {
    padding: 12px 16px;
    background: #f5f5f5;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px;
}

.thread-reply {
    padding: 8px 0;
    border-bottom: 1px solid #f0f0f0;
}

.thread-reply:last-child {
    border-bottom: none;
}

